import{_ as e,o,c as r,ag as a}from"./chunks/framework.6MCaaFDc.js";const u=JSON.parse('{"title":"What is Computing?","description":"","frontmatter":{},"headers":[],"relativePath":"theory/systems/what-is-computing.md","filePath":"theory/systems/what-is-computing.md"}'),n={name:"theory/systems/what-is-computing.md"};function s(d,t,i,c,l,m){return o(),r("div",null,[...t[0]||(t[0]=[a('<h1 id="what-is-computing" tabindex="-1">What is Computing? <a class="header-anchor" href="#what-is-computing" aria-label="Permalink to &quot;What is Computing?&quot;">​</a></h1><p>Your phone, your laptop, the traffic light at the corner — they all process information. Before you can understand <em>how</em> they do it, you need to understand <em>what</em> a computer actually is.</p><hr><h2 id="definitions" tabindex="-1">Definitions <a class="header-anchor" href="#definitions" aria-label="Permalink to &quot;Definitions&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Term</th><th>Definition</th></tr></thead><tbody><tr><td><strong>IT (Information Technology)</strong></td><td>The use of computers and software to manage, store, process and communicate information</td></tr><tr><td><strong>ICT (Information &amp; Communication Technology)</strong></td><td>IT <em>plus</em> communication technology — combining computing with networks and the internet</td></tr><tr><td><strong>Computer</strong></td><td>An electronic device that accepts data as input, processes it, stores results and produces output</td></tr><tr><td><strong>Data</strong></td><td>Raw, unprocessed facts and figures (e.g. the number <code>37</code>)</td></tr><tr><td><strong>Information</strong></td><td>Data that has been processed and given meaning (e.g. &quot;the temperature is 37°C&quot;)</td></tr><tr><td><strong>Knowledge</strong></td><td>Applying information to make decisions (e.g. &quot;37°C is a fever — see a doctor&quot;)</td></tr></tbody></table><div class="note custom-block github-alert"><p class="custom-block-title">Grade 10 — Foundation</p><p>This entire page is core Grade 10 content. Know all definitions and the computer model cold.</p></div><hr><h2 id="the-general-computer-model" tabindex="-1">The General Computer Model <a class="header-anchor" href="#the-general-computer-model" aria-label="Permalink to &quot;The General Computer Model&quot;">​</a></h2><p>Every computer — from a microcontroller to a high-end workstation — follows the same basic model:</p><table tabindex="0"><thead><tr><th>Component</th><th>Role</th><th>Examples</th></tr></thead><tbody><tr><td><strong>Input</strong></td><td>Gets data into the computer</td><td>Keyboard, mouse, microphone, scanner, webcam, touchscreen</td></tr><tr><td><strong>Process</strong></td><td>Manipulates and transforms data</td><td>CPU (Central Processing Unit)</td></tr><tr><td><strong>Output</strong></td><td>Presents results to the user</td><td>Monitor, printer, speaker, projector</td></tr><tr><td><strong>Storage</strong></td><td>Keeps data short-term or long-term</td><td>RAM (short-term), HDD/SSD/USB (long-term)</td></tr><tr><td><strong>Communication</strong></td><td>Sends/receives data to/from other devices</td><td>Network card, modem, Wi-Fi adapter</td></tr></tbody></table><div class="tip custom-block github-alert"><p class="custom-block-title">Exam Tip</p><p>The acronym <strong>IPOSC</strong> (Input → Process → Output → Storage → Communication) helps you remember the model. Most exam questions give you a device and ask which component role it plays.</p></div><hr><h2 id="hardware-vs-software" tabindex="-1">Hardware vs Software <a class="header-anchor" href="#hardware-vs-software" aria-label="Permalink to &quot;Hardware vs Software&quot;">​</a></h2><table tabindex="0"><thead><tr><th></th><th>Hardware</th><th>Software</th></tr></thead><tbody><tr><td><strong>What it is</strong></td><td>Physical components you can touch</td><td>Programs and instructions the computer runs</td></tr><tr><td><strong>Examples</strong></td><td>CPU, RAM, keyboard, monitor</td><td>Windows, Delphi, MS Word</td></tr><tr><td><strong>Types</strong></td><td>Input, output, storage, processing, communication</td><td>System software, application software</td></tr><tr><td><strong>Can be changed?</strong></td><td>Must be physically replaced</td><td>Installed, updated, deleted</td></tr></tbody></table><hr><h2 id="data-vs-information-vs-knowledge" tabindex="-1">Data vs Information vs Knowledge <a class="header-anchor" href="#data-vs-information-vs-knowledge" aria-label="Permalink to &quot;Data vs Information vs Knowledge&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Level</th><th>What it is</th><th>Example</th></tr></thead><tbody><tr><td><strong>Data</strong></td><td>Raw, unprocessed facts</td><td><code>37</code>, <code>John</code>, <code>Cape Town</code></td></tr><tr><td><strong>Information</strong></td><td>Data processed and given context</td><td>John&#39;s temperature is 37°C</td></tr><tr><td><strong>Knowledge</strong></td><td>Using information to make decisions</td><td>37°C is a fever — John needs to rest and see a doctor</td></tr></tbody></table><hr><h2 id="advantages-of-using-computers" tabindex="-1">Advantages of Using Computers <a class="header-anchor" href="#advantages-of-using-computers" aria-label="Permalink to &quot;Advantages of Using Computers&quot;">​</a></h2><ol><li>Provides access to more information</li><li>Completes tasks that might be impossible for humans (e.g. weather modelling, space calculations)</li><li>Saves time</li><li>Automates repetitive tasks</li><li>Allows for greater productivity</li><li>Allows for better communication and connections</li><li>Entertainment</li></ol><hr><h2 id="disadvantages-of-using-computers" tabindex="-1">Disadvantages of Using Computers <a class="header-anchor" href="#disadvantages-of-using-computers" aria-label="Permalink to &quot;Disadvantages of Using Computers&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Disadvantage</th><th>Explanation</th></tr></thead><tbody><tr><td><strong>Social risks</strong></td><td>Social media can be addictive, cause jealousy, and interfere with real friendships</td></tr><tr><td><strong>Health risks</strong></td><td>Excessive use causes back pain, eyestrain, obesity, <strong>RSI</strong>, and <strong>CTS</strong></td></tr><tr><td><strong>Security risks</strong></td><td>Malware can attack systems, destroy files, steal data or allow unauthorised access</td></tr><tr><td><strong>High cost</strong></td><td>Even affordable computers are expensive for many South Africans</td></tr><tr><td><strong>Distractions</strong></td><td>High entertainment value makes it easy to lose focus and productivity</td></tr><tr><td><strong>Environmental impact</strong></td><td>Computers consume large amounts of electricity; e-waste is a growing problem</td></tr></tbody></table><div class="note custom-block github-alert"><p class="custom-block-title">Key Terms</p><p><strong>RSI (Repetitive Strain Injury)</strong> — painful inflammation of tendons caused by overuse (e.g. excessive typing or mouse use)<br><strong>CTS (Carpal Tunnel Syndrome)</strong> — compression of the nerve in the wrist from repetitive hand/wrist movements<br><strong>Ergonomics</strong> — the study of how humans interact with manufactured objects, aiming to create environments suited to users&#39; physical needs</p></div><hr><h2 id="key-terms" tabindex="-1">Key Terms <a class="header-anchor" href="#key-terms" aria-label="Permalink to &quot;Key Terms&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Term</th><th>Definition</th></tr></thead><tbody><tr><td>Data</td><td>Raw, unprocessed facts</td></tr><tr><td>Information</td><td>Processed data with meaning</td></tr><tr><td>Knowledge</td><td>Information applied to make decisions</td></tr><tr><td>Hardware</td><td>Physical components of a computer</td></tr><tr><td>Software</td><td>Programs and instructions</td></tr><tr><td>IT</td><td>Information Technology</td></tr><tr><td>ICT</td><td>Information and Communication Technology</td></tr><tr><td>CPU</td><td>Central Processing Unit — the processor</td></tr><tr><td>Input device</td><td>Gets data into the computer</td></tr><tr><td>Output device</td><td>Presents results to the user</td></tr><tr><td>RSI</td><td>Repetitive Strain Injury</td></tr><tr><td>Ergonomics</td><td>Designing equipment for human comfort and efficiency</td></tr></tbody></table><hr><h2 id="exam-focus-—-paper-2" tabindex="-1">Exam Focus — Paper 2 <a class="header-anchor" href="#exam-focus-—-paper-2" aria-label="Permalink to &quot;Exam Focus — Paper 2&quot;">​</a></h2><ul><li><strong>Define</strong> IT, ICT, data, information, knowledge</li><li><strong>Explain</strong> the computer model (IPOSC) and give examples of each component</li><li><strong>Classify</strong> a given device: input / output / storage / processing / communication</li><li><strong>Distinguish</strong> between hardware and software with examples</li><li><strong>Give TWO advantages</strong> and <strong>TWO disadvantages</strong> of computers</li><li><strong>Define</strong> RSI and name ONE way to prevent it</li></ul>',30)])])}const g=e(n,[["render",s]]);export{u as __pageData,g as default};
